"use client";

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Search, Trophy, Home, List, Users, 
  ChevronRight, Crown, Activity, 
  ChevronLeft, Copy, Shield, X, Swords, Crosshair,
  Zap, Anchor, Target, Flame, BoxSelect, ShieldAlert,
  Terminal, Cpu, Globe, Radio
} from 'lucide-react';
import playersData from '../data/players.json';

export default function McTierUltimate() {
  // --- CORE STATE ---
  const [currentView, setCurrentView] = useState("Rankings"); // Switches Sidebar Views
  const [activeTab, setActiveTab] = useState("Overall"); // Switches Kit Filters
  const [search, setSearch] = useState("");
  const [isExpanded, setIsExpanded] = useState(false);
  const [copied, setCopied] = useState(false);
  const [selectedPlayer, setSelectedPlayer] = useState<any | null>(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => { setMounted(true); }, []);

  const kitTabs = ["Overall", "Crystal", "Sword", "UHC", "Axe", "Neth Pot", "SMP", "Tank", "Anchor", "Boxing"];

  const handleCopy = () => {
    navigator.clipboard.writeText("play.nordenmc.com");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getTierStyles = (tier: string) => {
    const t = tier?.toUpperCase() || "";
    if (t.includes('HT1')) return 'text-red-500 border-red-500/50 bg-red-500/10 shadow-[0_0_30px_rgba(239,68,68,0.4)] ring-1 ring-red-500/30';
    if (t.includes('LT1')) return 'text-cyan-400 border-cyan-500/50 bg-cyan-500/10 shadow-[0_0_30px_rgba(6,182,212,0.4)] ring-1 ring-cyan-500/30';
    if (t.includes('T2')) return 'text-purple-400 border-purple-500/40 bg-purple-500/10 shadow-[0_0_20px_rgba(168,85,247,0.3)]';
    return 'text-gray-400 border-white/10 bg-white/5';
  };

  const filteredPlayers = useMemo(() => {
    const data = Array.isArray(playersData) ? playersData : [];
    return data
      .filter((p: any) => {
        const nameMatch = p.name?.toLowerCase().includes(search.toLowerCase());
        const tabMatch = activeTab === "Overall" || p.kit === activeTab;
        return nameMatch && tabMatch;
      })
      .sort((a: any, b: any) => (a.rank || 99) - (b.rank || 99));
  }, [search, activeTab]);

  if (!mounted) return null;

  return (
    <div className="flex min-h-screen bg-[#020203] text-[#e1e1e3] font-sans selection:bg-cyan-500/40 overflow-hidden">
      
      {/* --- SIDEBAR (FUNCTIONAL TABS) --- */}
      <aside className={`flex flex-col py-10 border-r border-white/5 bg-[#050507] transition-all duration-700 cubic-bezier(0.16, 1, 0.3, 1) z-[100] relative ${isExpanded ? 'w-72 px-8' : 'w-24 items-center'}`}>
        <div onClick={() => setIsExpanded(!isExpanded)} className="mb-14 cursor-pointer text-cyan-500 bg-cyan-500/10 p-4 rounded-2xl border border-cyan-500/20 hover:shadow-[0_0_40px_rgba(6,182,212,0.4)] transition-all group">
          {isExpanded ? <ChevronLeft size={28} /> : <Terminal size={28} className="group-hover:rotate-12" />}
        </div>
        
        <nav className="flex flex-col gap-8 w-full">
          {[
            { id: "Home", icon: <Home size={24} />, label: "Nexus Hub" },
            { id: "Rankings", icon: <List size={24} />, label: "Global Tiers" },
            { id: "Staff", icon: <ShieldAlert size={24} />, label: "Staff Panel" },
            { id: "Community", icon: <Users size={24} />, label: "Guild Net" }
          ].map((item) => (
            <button 
              key={item.id}
              onClick={() => setCurrentView(item.id)}
              className={`flex items-center gap-6 p-4 rounded-2xl transition-all duration-500 group relative ${currentView === item.id ? 'bg-cyan-500/10 text-cyan-400' : 'text-gray-600 hover:text-gray-300'}`}
            >
              <div className={`transition-all duration-500 ${currentView === item.id ? 'scale-110 drop-shadow-[0_0_10px_rgba(6,182,212,0.8)]' : 'group-hover:scale-110'}`}>
                {item.icon}
              </div>
              {isExpanded && <span className="font-black uppercase tracking-[0.2em] text-[11px] leading-none">{item.label}</span>}
              {currentView === item.id && <div className="absolute right-0 w-1 h-8 bg-cyan-500 rounded-l-full shadow-[0_0_20px_#22d3ee]"></div>}
            </button>
          ))}
        </nav>

        {/* Floating User Profile at Bottom */}
        <div className="mt-auto group cursor-pointer">
          <div className="w-12 h-12 rounded-2xl bg-gradient-to-tr from-cyan-600 to-blue-700 border border-white/20 flex items-center justify-center font-black shadow-[0_0_20px_rgba(6,182,212,0.3)] group-hover:scale-110 transition-transform">
            N
          </div>
        </div>
      </aside>

      {/* --- MAIN CONTENT AREA --- */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto custom-scrollbar relative">
        
        {/* TOP STATUS OVERLAY */}
        <div className="bg-[#050507]/60 backdrop-blur-md border-b border-white/5 py-4 px-12 flex items-center justify-between sticky top-0 z-50">
          <div className="flex items-center gap-6">
            <h1 className="text-2xl font-black italic tracking-tighter text-white uppercase group">
              Norden<span className="text-cyan-500 group-hover:drop-shadow-[0_0_10px_#22d3ee] transition-all">MC</span>
            </h1>
            <div className="h-4 w-px bg-white/10"></div>
            <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.3em] text-cyan-400/70">
              <Radio size={12} className="animate-pulse" /> {currentView} Link Established
            </div>
          </div>
          
          <div className="flex items-center gap-8">
            <div className="relative group">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-cyan-500 transition-colors" size={16} />
               <input 
                 type="text" 
                 placeholder="Search Database..." 
                 className="bg-white/[0.03] border border-white/5 rounded-xl py-2 pl-12 pr-6 outline-none focus:border-cyan-500/30 transition-all text-[10px] font-black uppercase tracking-widest w-64"
                 value={search}
                 onChange={(e) => setSearch(e.target.value)}
               />
            </div>
            <button onClick={handleCopy} className="text-[10px] font-black uppercase tracking-widest bg-cyan-500 text-black px-5 py-2 rounded-lg shadow-[0_0_20px_rgba(6,182,212,0.3)] hover:scale-105 transition-all">
              {copied ? "Copied!" : "play.nordenmc.com"}
            </button>
          </div>
        </div>

        {/* DYNAMIC VIEW SWITCHER */}
        <main className="p-12 max-w-[1500px] mx-auto w-full animate-in fade-in slide-in-from-bottom-4 duration-1000">
          
          {currentView === "Rankings" && (
            <div className="space-y-16">
              {/* TOP PODIUM (GLASS CARDS) */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                {filteredPlayers.slice(0, 3).map((p, i) => (
                  <div key={p.name} onClick={() => setSelectedPlayer(p)} className="relative group cursor-pointer">
                    <div className="absolute inset-0 bg-gradient-to-br from-cyan-500/20 to-transparent blur-3xl opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>
                    <div className="bg-[#0a0a0d] border border-white/5 p-10 rounded-[3rem] relative z-10 hover:border-cyan-500/40 hover:-translate-y-4 transition-all duration-700">
                       <div className="flex flex-col items-center text-center gap-6">
                         <div className="relative">
                           <img src={`https://mc-heads.net/avatar/${p.name}/120`} className="w-28 h-28 rounded-3xl border-2 border-white/10 group-hover:rotate-6 transition-all duration-500 shadow-2xl" alt="" />
                           <div className="absolute -top-4 -right-4 bg-[#050507] p-3 rounded-2xl border border-white/10 text-yellow-500 shadow-xl">
                             <Crown size={24} />
                           </div>
                         </div>
                         <div>
                           <h3 className="text-3xl font-black italic uppercase tracking-tighter text-white mb-2">{p.name}</h3>
                           <p className="text-[10px] font-black tracking-[0.4em] text-cyan-500 uppercase">Global Rank #0{p.rank}</p>
                         </div>
                       </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* FILTER SYSTEM */}
              <div className="flex items-center justify-between border-b border-white/5 pb-8">
                 <div className="flex items-center gap-3">
                    {kitTabs.map(tab => (
                      <button 
                        key={tab} 
                        onClick={() => setActiveTab(tab)}
                        className={`px-6 py-3 rounded-xl text-[9px] font-black uppercase tracking-[0.2em] transition-all ${activeTab === tab ? 'bg-white text-black shadow-xl scale-105' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
                      >
                        {tab}
                      </button>
                    ))}
                 </div>
                 <div className="text-[10px] font-black uppercase tracking-[0.4em] text-gray-700">
                    S1 Database // {filteredPlayers.length} Records
                 </div>
              </div>

              {/* MASTER LIST (HYPER-DETAILED) */}
              <div className="space-y-4">
                {filteredPlayers.map((player: any) => (
                  <div 
                    key={player.name} 
                    onClick={() => setSelectedPlayer(player)}
                    className="grid grid-cols-12 gap-6 p-6 items-center bg-[#0a0a0d] border border-white/[0.03] rounded-[2rem] hover:bg-white/[0.02] hover:border-cyan-500/30 transition-all duration-500 group cursor-pointer"
                  >
                    <div className="col-span-1 text-4xl font-black italic text-gray-900 group-hover:text-cyan-500/20 transition-colors pl-4">
                      {player.rank.toString().padStart(2, '0')}
                    </div>
                    <div className="col-span-7 flex items-center gap-8">
                      <img src={`https://mc-heads.net/avatar/${player.name}/100`} className="w-16 h-16 rounded-2xl border border-white/5 group-hover:scale-110 group-hover:rotate-2 transition-all duration-500" alt="" />
                      <div>
                        <div className="font-black text-2xl text-white uppercase italic tracking-tighter flex items-center gap-4">
                          {player.name} 
                          <span className="text-[9px] not-italic font-black bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 px-3 py-1 rounded-md">PRO Contender</span>
                        </div>
                        <div className="flex items-center gap-4 mt-2 text-[10px] font-black uppercase tracking-widest text-gray-600">
                           <Activity size={14} className="text-cyan-500" /> {player.kit} discipline
                           <div className="w-1 h-1 rounded-full bg-white/20"></div>
                           <span className="text-green-500/60">System Online</span>
                        </div>
                      </div>
                    </div>
                    <div className="col-span-4 flex justify-end items-center gap-10 pr-6">
                       <div className={`px-10 py-3 rounded-xl font-black italic text-2xl tracking-tighter transition-all duration-700 group-hover:scale-110 ${getTierStyles(player.tier)}`}>
                         {player.tier}
                       </div>
                       <div className="w-12 h-12 rounded-2xl border border-white/5 flex items-center justify-center text-gray-800 group-hover:bg-cyan-500 group-hover:text-black transition-all">
                          <ChevronRight size={24} />
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {currentView === "Staff" && (
            <div className="h-[60vh] flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in zoom-in duration-700">
               <div className="p-10 bg-cyan-500/5 border border-cyan-500/20 rounded-[3rem] shadow-[0_0_50px_rgba(6,182,212,0.1)]">
                  <ShieldAlert size={80} className="text-cyan-500 mx-auto mb-6 animate-pulse" />
                  <h2 className="text-4xl font-black uppercase italic tracking-tighter mb-4">Staff Command Center</h2>
                  <p className="text-gray-500 font-bold tracking-widest uppercase text-xs max-w-md mx-auto leading-relaxed">
                    Accessing NordenMC core infrastructure. Please authenticate with system credentials to view moderator logs and server metrics.
                  </p>
               </div>
               <button className="px-12 py-4 bg-white text-black font-black uppercase tracking-widest rounded-2xl hover:bg-cyan-400 transition-all shadow-2xl">
                 Authenticate Session
               </button>
            </div>
          )}

          {currentView === "Home" && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 animate-in fade-in slide-in-from-left-8 duration-700">
               <div className="bg-[#0a0a0d] border border-white/5 p-12 rounded-[3rem] space-y-6">
                  <Globe size={40} className="text-cyan-500" />
                  <h2 className="text-4xl font-black italic uppercase tracking-tighter text-white">Network Portal</h2>
                  <p className="text-gray-500 font-bold uppercase tracking-widest text-xs leading-loose">
                    Welcome to the central node of the NordenMC competitive network. Here you can track global standings, manage your guild profile, and monitor server health across all regions.
                  </p>
                  <div className="grid grid-cols-2 gap-4 mt-8">
                     <div className="p-6 bg-white/5 rounded-2xl border border-white/5">
                        <p className="text-[10px] font-black text-gray-600 uppercase mb-2">Network Load</p>
                        <p className="text-2xl font-black italic">42.8%</p>
                     </div>
                     <div className="p-6 bg-white/5 rounded-2xl border border-white/5">
                        <p className="text-[10px] font-black text-gray-600 uppercase mb-2">Live Nodes</p>
                        <p className="text-2xl font-black italic text-cyan-500">2,109</p>
                     </div>
                  </div>
               </div>
               <div className="bg-gradient-to-br from-[#0a0a0d] to-cyan-950/20 border border-white/5 p-12 rounded-[3rem] flex flex-col justify-end">
                  <Cpu size={60} className="text-cyan-400 mb-8 opacity-20" />
                  <h3 className="text-5xl font-black italic uppercase tracking-tighter text-white leading-[0.9]">Master<br/><span className="text-cyan-500">Architecture</span></h3>
                  <p className="text-[10px] font-black uppercase tracking-[0.5em] text-cyan-500/50 mt-6">Version 4.2.0 // Secured</p>
               </div>
            </div>
          )}

        </main>
      </div>

      {/* --- HYPER-GUI MODAL --- */}
      {selectedPlayer && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-3xl z-[300] flex items-center justify-center p-8 animate-in fade-in duration-500" onClick={() => setSelectedPlayer(null)}>
           <div className="bg-[#050507] border border-white/10 rounded-[4rem] w-full max-w-4xl overflow-hidden shadow-[0_0_150px_rgba(0,0,0,1)] relative" onClick={e => e.stopPropagation()}>
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500 to-transparent shadow-[0_0_20px_#22d3ee]"></div>
              
              <div className="grid grid-cols-12 h-[600px]">
                 {/* Left Profile Side */}
                 <div className="col-span-5 bg-white/[0.02] border-r border-white/5 p-16 flex flex-col items-center justify-center text-center">
                    <div className="relative mb-10">
                       <div className="absolute inset-0 bg-cyan-500 blur-[80px] rounded-full opacity-20 animate-pulse"></div>
                       <img src={`https://mc-heads.net/avatar/${selectedPlayer.name}/200`} className="w-48 h-48 rounded-[3rem] relative z-10 border-4 border-[#050507] shadow-2xl" alt="" />
                    </div>
                    <h2 className="text-5xl font-black italic tracking-tighter uppercase text-white mb-4">{selectedPlayer.name}</h2>
                    <div className={`px-10 py-4 rounded-2xl font-black italic text-3xl ${getTierStyles(selectedPlayer.tier)}`}>
                       {selectedPlayer.tier}
                    </div>
                 </div>

                 {/* Right Data Side */}
                 <div className="col-span-7 p-16 relative">
                    <button onClick={() => setSelectedPlayer(null)} className="absolute top-10 right-10 text-gray-600 hover:text-white transition-colors"><X size={32} /></button>
                    
                    <div className="space-y-12">
                       <div>
                          <p className="text-[10px] font-black uppercase tracking-[0.5em] text-cyan-500 mb-6 flex items-center gap-3">
                             <Crosshair size={14} /> System Profile Scan
                          </p>
                          <div className="grid grid-cols-2 gap-8">
                             <div>
                                <p className="text-[10px] font-black uppercase tracking-widest text-gray-600 mb-2">Global Standing</p>
                                <p className="text-4xl font-black italic text-white">#{selectedPlayer.rank}</p>
                             </div>
                             <div>
                                <p className="text-[10px] font-black uppercase tracking-widest text-gray-600 mb-2">Kit Specialization</p>
                                <p className="text-4xl font-black italic text-white">{selectedPlayer.kit || "Hybrid"}</p>
                             </div>
                          </div>
                       </div>

                       <div>
                          <p className="text-[10px] font-black uppercase tracking-widest text-gray-500 mb-4">Combat Power Output</p>
                          <div className="h-6 w-full bg-white/5 rounded-full border border-white/5 p-1.5 overflow-hidden">
                             <div className="h-full bg-gradient-to-r from-cyan-600 to-cyan-400 rounded-full shadow-[0_0_20px_#22d3ee] animate-in slide-in-from-left duration-1000" style={{ width: '88%' }}></div>
                          </div>
                       </div>

                       <div className="pt-10 border-t border-white/5 grid grid-cols-3 gap-6">
                          {['Aggression', 'Reflex', 'Consistency'].map(stat => (
                             <div key={stat} className="text-center">
                                <p className="text-[9px] font-black uppercase text-gray-600 mb-2 tracking-widest">{stat}</p>
                                <div className="text-xl font-black italic text-cyan-500/80">9.4/10</div>
                             </div>
                          ))}
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* Background Decor */}
      <div className="fixed top-0 right-0 w-[800px] h-[800px] bg-cyan-600/5 blur-[150px] rounded-full -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>
    </div>
  );
}